noncompliant:
void ambiguousConstants() {
    // These constants may be signed or unsigned depending on platform
    unsigned int mask = 0x80000000;     // Noncompliant - ambiguous in 32-bit
    unsigned long flags = 0xFFFFFFFF;    // Noncompliant - missing U suffix
    unsigned short port = 65535;        // Noncompliant - could overflow

    // Hexadecimal constants are particularly problematic
    unsigned int addr = 0xDEADBEEF;     // Noncompliant
}

compliant:
void clearConstants() {
    // Use U suffix for unsigned constants
    unsigned int mask = 0x80000000U;     // Compliant - clearly unsigned
    unsigned long flags = 0xFFFFFFFFU;   // Compliant - U suffix
    unsigned short port = 65535U;        // Compliant - U suffix

    // Or use UL for unsigned long
    unsigned long addr = 0xDEADBEEFUL;   // Compliant

    // For very large numbers, use ULL
    unsigned long long bigNum = 0x123456789ABCDEFULL; // Compliant
}
